"""
MKT Original Commentary — Proverbs chapters 19–21
Run: python3 scripts/zc-original-proverbs-19-21.py
Key translation decisions:
- tōm: "integrity" (19:1) — completeness, wholeness, the undivided person
- ḥesed: "faithful love / steadfast love" (19:22; 20:28; 21:21) — covenant loyalty
- nišmat ʾādām nēr YHWH: "human spirit is the LORD's lamp" (20:27) — divine searching of conscience
- yēšûʿāh laYHWH: "victory belongs to the LORD" (21:31) — not yeshuah as personal name
- 21:3: righteousness + justice > sacrifice — the prophetic critique of empty ritual
- 20:9: the rhetorical question of universal sinfulness — no one can claim pure heart
"""

import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

new_data = {
    "19": {
        "1": "<p>&#8220;Better is a poor man who walks in his integrity (<i>tōm</i>).&#8221; The <i>ṭôb min</i> (better than) comparison formula is a characteristic wisdom device used to challenge conventional valuations. <i>Tōm</i> (integrity, wholeness, completeness — from <i>tāmam</i>, to be whole) describes the undivided person who is the same inside and outside (cf. 28:6 for the near-identical doublet). &#8220;Crooked in speech (<i>ʿiqqēš śᵉpātāyw</i>)&#8221; — the twisted-lipped person, morally deformed speech as the indicator of inner corruption. Integrity and poverty outrank wealth and deception in Proverbs&#8217; hierarchy of values.</p>",
        "2": "<p>&#8220;Desire (<i>nepeš</i>) without knowledge is not good.&#8221; <i>Nepeš</i> here is appetite, craving, the drive of the self — used as the seat of desire (cf. 16:26). Without <i>da&#x2BF;at</i> (knowledge, discernment) to guide it, strong desire becomes reckless. &#8220;The one who moves too fast (<i>ʾāṣ bᵉraglāyw</i> = hurries with his feet) misses the way (<i>ḥōṭēʾ</i>).&#8221; <i>Ḥāṭāʾ</i> (to miss, to sin — the basic sin-word: to miss the target or the road) — haste causes a person to miss the path. The antidote is deliberate, knowledge-guided movement.</p>",
        "3": "<p>&#8220;A man&#8217;s own foolishness (<i>iwwelet</i>) leads his way astray (<i>tᵉsallēp darkô</i>), yet his heart rages (<i>yizʿap</i>) against the LORD.&#8221; <i>Sālap</i> (hiphil: to subvert, twist, overturn — cf. 13:6; 21:12) describes how folly inverts the normal order. <i>Zāʿap</i> (to rage, to be vexed — the same word for Jonah&#8217;s anger, Jonah&#160;4:1) — the fool blames God for the consequences of his own choices. The psychological insight is sharp: self-caused disaster generates God-directed resentment rather than self-examination.</p>",
        "4": "<p>&#8220;Wealth (<i>hôn</i>) attracts many friends (<i>yaôsip rēʿîm rabbîm</i>), but the poor man (<i>dāl</i>) is separated (<i>yippārēd</i>) from his neighbor.&#8221; A social observation rather than a moral prescription — Proverbs regularly notes how wealth and poverty function in society without endorsing the outcome. <i>Pārad</i> (to divide, separate — cf. Gen&#160;13:9; Prov&#160;17:9) — poverty creates social distance. The contrast with 17:17 (a friend loves at all times) is pointed: wealth attracts fair-weather friends; true friendship is tested by poverty.</p>",
        "5": "<p>&#8220;A false witness (<i>ʿēd šᵉqārim</i>) will not go unpunished (<i>lōʾ-yinnāqeh</i>).&#8221; The declaration uses the niphal of <i>nāqāh</i> (to be clean, innocent, acquitted — Exod&#160;34:7; Num&#160;14:18). False witness is an assault on justice at its root; the declaratory formula states divine certainty of consequence (cf. v9 for a near-identical pair). The ninth commandment (Exod&#160;20:16) is the legal background for this repeated warning in Proverbs (6:19; 12:17; 14:5, 25).</p>",
        "6": "<p>&#8220;Many seek (<i>yᵉḥallû</i>) the favor (<i>pᵉnê</i>) of a generous man (<i>nādîb</i>); everyone is a friend (<i>rēaʿ</i>) to the one who gives gifts (<i>mattan</i>).&#8221; <i>Ḥālāh</i> (piel: to entreat, seek the face of — cf. Ps&#160;45:12; Mal&#160;1:9) is a courtly gesture of seeking favor. <i>Nādîb</i> (noble, generous person — one who gives freely, from <i>nādab</i>, to volunteer, give willingly) is contrasted with the king of v12. The verse observes without condemning: generosity creates social bonds, but their quality depends on whether the giver notices who is only there for the gifts.</p>",
        "7": "<p>&#8220;All the brothers of a poor man hate him (<i>śānᵉʾûhû</i>) — how much more do his friends keep their distance (<i>rᵉḥēqû mimenû</i>).&#8221; The argument <i>qal wāḥōmer</i> (light to heavy): if brothers, with kinship bonds, hate the poor man, how much more mere friends. The final colon — &#8220;he may call after them (<i>mᵉraddep ʾᵃmārîm</i>), but they are gone (<i>lōʾ-hēmmāh</i>)&#8221; — is difficult and perhaps textually awkward; the sense is the poor man calling after departed friends who no longer exist for him. Poverty&#8217;s social isolation is its bitterest dimension.</p>",
        "8": "<p>&#8220;Whoever acquires wisdom (<i>qānāh-lēb</i> = acquires a heart/mind) loves himself (<i>ʾōhēb napšô</i>).&#8221; <i>Qānāh</i> (to acquire, get — cf. 4:5, 7; 8:22 where Wisdom is acquired/created by God) — wisdom is something you can buy and own. &#8220;Loves himself (<i>napšô</i>)&#8221; — in a striking formulation, self-love is here the positive motivation for wisdom: to pursue wisdom is to care properly for oneself. &#8220;Whoever holds to (<i>šōmēr</i>) understanding (<i>tᵉbûnāh</i>) will find what is good (<i>limsōʾ-ṭôb</i>)&#8221; — keeping wisdom is keeping oneself in the way of flourishing.</p>",
        "9": "<p>&#8220;Whoever breathes out lies (<i>mᵉpiaḥ kᵉzābîm</i>) will perish (<i>yōʾbēd</i>).&#8221; The variant ending of v5 — there, &#8220;will not escape&#8221; (<i>lōʾ-yimmālet</i>); here, &#8220;will perish&#8221; (<i>yōʾbēd</i>, the destruction-verb) — intensifies the consequence. <i>Pûaḥ</i> (to breathe out, puff) suggests effortless, habitual lying. The doubling of the false-witness warning in vv5 and 9 gives it the emphasis of a refrain — one of the most condemned behaviors in Proverbs.</p>",
        "10": "<p>&#8220;Luxury (<i>taʿᵃnûg</i>) does not suit (<i>lōʾ-nāʾweh</i>) a fool.&#8221; <i>Nāweh</i> (fitting, becoming — used of a beautiful pasture in Ps&#160;93:5; Song&#160;1:5) — luxury on a fool is aesthetically and morally wrong, a mismatch. &#8220;Even worse for a slave to rule over princes (<i>mišneh kî-ʿebed yimšōl bᵉśārîm</i>)&#8221; — <i>mišneh</i> (double, much more) escalates to the social order: a slave ruling over princes is a sign of social inversion (cf. 30:21&#8211;23; Eccl&#160;10:7). The verse addresses the category of fitness: things must match their proper level.</p>",
        "11": "<p>&#8220;A man&#8217;s wisdom (<i>śekel</i>) makes him slow to anger (<i>heʾĕrîk ʾappô</i>).&#8221; <i>Śekel</i> (insight, prudent wisdom) slows the anger response — the wise person delays reaction in order to perceive correctly. &#8220;It is his glory (<i>tipʾartô</i>) to overlook (<i>laʿᵃbōr ʿal</i>) an offense (<i>peša&#x2BF;</i>).&#8221; <i>Pāšaʿ</i> (rebellion, transgression — cf. Amos&#160;1:3; Ps&#160;51:1) is a strong word for offense; to pass over it (<i>ʿābar</i>) is an act of sovereign restraint. The wisdom that can absorb an affront without retaliation is described as glory (<i>tipʾeret</i> — cf. Exod&#160;28:2 for priestly glory; Prov&#160;4:9), not weakness.</p>",
        "12": "<p>&#8220;A king&#8217;s wrath (<i>zaʿap-melek</i>) is like the roaring (<i>kᵉnaham</i>) of a lion (<i>kᵉpîr</i>), but his favor (<i>rᵉṣônô</i>) is like dew (<i>ṭal</i>) upon the grass.&#8221; The lion and dew comparison for royal power appears also in 20:2 and 16:15. <i>Kᵉpîr</i> (young lion — the most dangerous and aggressive) for royal wrath; <i>ṭal</i> (dew — the gentle moisture that falls overnight, source of life in Palestine&#8217;s dry season) for royal favor. The king&#8217;s power to destroy or to nourish is absolute.</p>",
        "13": "<p>&#8220;A foolish son (<i>bēn kᵉsîl</i>) is ruin (<i>hawwōt</i>) to his father, and a wife&#8217;s quarreling (<i>midyanê ʾišāh</i>) is like a constant drip (<i>ṭēret dôlep</i>).&#8221; <i>Hawwāh</i> (ruin, calamity, disaster — from <i>hāwāh</i>, to fall, come to nothing; cf. Job&#160;6:2; Ps&#160;38:12) is the word for utter destruction. The dripping roof metaphor (<i>ṭārap</i> = dripping; <i>dōlep</i> = rain, dripping) recurs in 27:15 — the irritation of unceasing minor agitation wearing down the one who endures it.</p>",
        "14": "<p>&#8220;A house and wealth (<i>hôn</i>) can be inherited from one&#8217;s father, but a sensible wife (<i>ʾišāh maśkîlet</i>) comes from (<i>mēʾēt</i>) the LORD.&#8221; Two categories of good: the transferable (property, money) and the non-transferable (a wise wife). <i>Maśkîlet</i> (prudent, insightful — the hiphil participle of <i>śākal</i>) designates a woman of practical wisdom. That she &#8220;comes from the LORD&#8221; places her in the category of divine gift, like wisdom itself (2:6) — she cannot be earned or inherited, only received.</p>",
        "15": "<p>&#8220;Laziness (<i>ʿaṣlāh</i>) brings on a deep sleep (<i>tardēmāh</i>), and the idle person (<i>nepeš rᵉmîyyāh</i>) will go hungry.&#8221; <i>Tardēmāh</i> (deep sleep — the sleep of stupor rather than rest; the same word for the sleep God placed on Adam in Gen&#160;2:21 and the deep sleep of the seers) conveys a stupefied paralysis. <i>Nepeš rᵉmîyyāh</i> (a slack soul — the soul without tension or drive) will find its fridge empty. The connection between sloth and hunger is one of Proverbs&#8217; most repeated practical teachings.</p>",
        "16": "<p>&#8220;Whoever keeps (<i>šōmēr</i>) the commandment (<i>miṣwāh</i>) keeps his life (<i>šōmēr napšô</i>); whoever is careless (<i>bôzēh</i>) about his conduct (<i>dᵉrākāyw</i>) will die.&#8221; The link between commandment-keeping and life is Deuteronomic at its core (Deut&#160;4:40; 6:2; 30:16). <i>Bāzāh</i> (to despise, treat with contempt) — carelessness toward one&#8217;s own conduct is an act of contempt toward the very structure of life. The symmetry is tight: the verb <i>šāmar</i> (to keep, guard) governs both commandment and life — keep the commandment and you keep yourself.</p>",
        "17": "<p>&#8220;Whoever is kind to the poor (<i>ḥônēn dāl</i>) lends to (<i>malweh</i>) the LORD, and he will repay him for his deed (<i>gᵉmûlô yᵉšallem-lô</i>).&#8221; The metaphor is audacious: a loan to God. <i>Māwāh</i> (to lend — cf. Exod&#160;22:25) transposes the act of charitable giving into a commercial transaction with divine security. The poor are so identified with God that helping them is extending credit to the Almighty. <i>Gāmal</i> (to repay, deal bountifully — cf. Ps&#160;13:6; 116:7; 119:17) guarantees the return.</p>",
        "18": "<p>&#8220;Discipline (<i>yassēr</i>) your son while there is still hope (<i>kî-yēš tiqwāh</i>); do not set your heart on his destruction (<i>ʾal-tittᵉ napšᵉkā lahᵃmîtô</i>).&#8221; The hope-window is temporal: there is a period when discipline can form character; after that period closes, it cannot. <i>Tiqwāh</i> (hope, expectation — from <i>qāwāh</i>, to wait, hope; also &#8220;cord&#8221; in Josh&#160;2:18) names the window of formability. &#8220;Do not set your heart on his destruction&#8221; — the negative caution: undisciplined indulgence (&#8220;letting him have his way&#8221;) actually leads toward the child&#8217;s death, not his flourishing.</p>",
        "19": "<p>&#8220;A man of great wrath (<i>gᵉdal-ḥēmāh</i>) will bear the penalty (<i>yiśśāʾ-ʿōneš</i>); if you rescue him (<i>ṣiltāh</i>), you will only have to do it again (<i>yôsip</i>).&#8221; <i>Ḥēmāh</i> (wrath, heat, poison — cf. 6:34; 27:4) — the hot-tempered man creates consequences. The second clause is a practical warning to would-be helpers: rescuing someone from the natural consequences of their hot temper does not change the temper; it enables the next episode. Proverbs here is psychologically astute about the limits of rescue.</p>",
        "20": "<p>&#8220;Listen to counsel (<i>šᵉmaʿ ʿēṣāh</i>) and accept instruction (<i>qabbēl mûsār</i>), that you may gain wisdom (<i>tᵉḥkam</i>) in the end (<i>bᵉʾaḥᵃrîtekā</i>).&#8221; The temporal horizon is key: wisdom is not always immediately gratifying; its fruit appears &#8220;in the end&#8221; (<i>ʾaḥᵃrît</i> — the latter end, the future outcome; cf. 5:11; 14:12; 23:18; 24:14). The willingness to receive counsel and correction now is the investment that pays wisdom later.</p>",
        "21": "<p>&#8220;Many are the plans (<i>maḥᵃšābôt</i>) in a man&#8217;s heart, but the LORD&#8217;s purpose (<i>ʿᵃṣat-YHWH</i>) is what stands (<i>hî&#702; tāqûm</i>).&#8221; <i>Maḥᵃšābāh</i> (plan, thought, design — from <i>ḥāšab</i>, to think, reckon, plan) versus <i>ʿēṣāh</i> (counsel, purpose, deliberate plan — the counsel of God that no human scheme can overturn). The sovereignty of divine purpose over human planning echoes 16:1, 9; 21:30&#8211;31. The human plans are numerous; the divine purpose is single and invincible.</p>",
        "22": "<p>&#8220;What is desired (<i>taʾᵃwat</i>) in a person is faithful love (<i>ḥasdô</i>), and a poor man is better than a liar.&#8221; The first clause is difficult: <i>taʾᵃwāh</i> (desire, what is longed for) combined with <i>ḥesed</i> (faithful love) may mean &#8220;the desirable quality in a person is his ḥesed&#8221; or &#8220;the desire a person inspires depends on his ḥesed.&#8221; Either way, <i>ḥesed</i> (covenant loyalty, steadfast love — here in the human virtue dimension) is the most desirable trait. The comparison &#8220;better a poor man than a liar&#8221; repeats 19:1&#8217;s poverty-integrity comparison with a different pairing.</p>",
        "23": "<p>&#8220;The fear of the LORD (<i>yirʾat-YHWH</i>) leads to life (<i>lᵉḥayyîm</i>); whoever has it will rest satisfied (<i>śābēaʿ yālîn</i>) and will not be touched by evil (<i>lōʾ-yippāqqēd rāʿāh</i>).&#8221; The programmatic thesis of 1:7 is here unfolded into its consequences: life, satisfaction, immunity from evil. <i>Lîn</i> (to lodge overnight, to stay — cf. Ps&#160;91:1) suggests the security of one who rests undisturbed. <i>Pāqad</i> (to visit, attend to, appoint — the same word used of God visiting Israel with judgment or blessing) — evil will not visit the one who fears the LORD.</p>",
        "24": "<p>&#8220;The sluggard (<i>ʿāṣēl</i>) buries (<i>ṭāman</i>) his hand in the dish and will not even bring it to his mouth again.&#8221; The most absurdist image in Proverbs — a man too lazy to complete the motion of eating. <i>Ṭāman</i> (to bury, hide — cf. 2:7; Gen&#160;35:4) — the hand is &#8220;buried&#8221; in the dish, inert. The verse is satirical, approaching caricature, but the point is precise: the extreme of sloth is self-starvation while food is available. The same image appears in 26:15.</p>",
        "25": "<p>&#8220;Strike (<i>hak</i>) a mocker (<i>lēṣ</i>) and the naive (<i>peta&#702;î</i>) will gain caution (<i>yaʿrum</i>); correct (<i>hôkîaḥ</i>) a man of understanding (<i>nābôn</i>) and he gains knowledge.&#8221; A ladder of responses to correction: the naive learns vicariously (watching punishment produces caution); the man of understanding learns directly from reproof. The mocker is not improved by his own punishment — its benefit falls on bystanders. Different levels of wisdom require different pedagogical approaches.</p>",
        "26": "<p>&#8220;A son who mistreats (<i>mᵉšaddēd</i>) his father and drives away (<i>mᵉbîaḥ</i>) his mother brings shame (<i>bôš</i>) and disgrace (<i>ḥerpāh</i>).&#8221; <i>Šādad</i> (to devastate, to rob by violence — cf. Isa&#160;21:2; Prov&#160;11:3) — the son who robs or crushes the father violates the foundation of the family order (Exod&#160;21:17; Prov&#160;20:20). <i>Ḥerpāh</i> (reproach, public shame — the worst social outcome) falls on the perpetrator, not the victim. The inversion of the fifth commandment brings maximum social disgrace.</p>",
        "27": "<p>&#8220;Stop listening (<i>ḥadal</i>) to instruction, my son, and you will drift (<i>lišgôt</i>) from words of knowledge.&#8221; A deliberately paradoxical address: the teacher tells the student to stop listening — as a warning about what results if they do. <i>Šāgāh</i> (to wander, go astray — the same root as drunken staggering in Isa&#160;28:7; Prov&#160;5:19&#8211;20) — ceasing to receive instruction produces moral wandering from knowledge. The verse makes audible the consequence of closing one&#8217;s ears.</p>",
        "28": "<p>&#8220;A corrupt witness (<i>ʿēd bᵉliyya&#702;al</i>) mocks justice (<i>yālîṣ mišpāṭ</i>), and the mouth of the wicked gulps down (<i>yᵉballa&#702;</i>) iniquity (<i>ʾāwen</i>).&#8221; <i>Bᵉliyya&#702;al</i> (worthlessness, the thing that profits nothing — the epithet of the person with no redeeming value; cf. 6:12; 1&#160;Sam&#160;2:12) — the &#8220;worthless witness&#8221; corrupts the entire judicial system. <i>Bālaʿ</i> (to swallow, gulp down — cf. 1:12 where Sheol swallows) — the wicked devour iniquity as food, consuming it greedily rather than being polluted by it accidentally.</p>",
        "29": "<p>&#8220;Penalties (<i>šᵉpāṭîm</i>) are set in store for mockers (<i>lēṣîm</i>), and beatings (<i>maḥᵃlumôt</i>) for the backs of fools (<i>ḥᵉsîlîm</i>).&#8221; The judicial term <i>šᵉpāṭ</i> (judgment, penalty) is normally used of divine or royal verdicts; here it is applied to the mocker&#8217;s inevitable fate. &#8220;Beatings for the backs of fools&#8221; — the corporal punishment designed for those who refuse verbal correction (cf. 17:10; 26:3). The chapter ends with the certainty of consequence for those who mock both wisdom and justice.</p>"
    },
    "20": {
        "1": "<p>&#8220;Wine (<i>yayin</i>) is a mocker (<i>lēṣ</i>) and strong drink (<i>šēkār</i>) a brawler (<i>hōmeh</i>); whoever is led astray (<i>šōgeh</i>) by it is not wise.&#8221; The personification of wine as a <i>lēṣ</i> (scoffer/mocker — the most dangerous human type in Proverbs) gives the substance the characteristics of the most destructive human character. <i>Hāmāh</i> (to roar, to be boisterous — used of the crowds, the sea, the city; cf. 1:21; 9:13; Ps&#160;46:3) — strong drink makes men riotous. <i>Šāgāh</i> (to stagger, go astray — as in 19:27) — the drunkard wanders from the path of wisdom.</p>",
        "2": "<p>&#8220;The terror (<i>ʾêmat</i>) of a king is like the roaring (<i>kᵉnaham</i>) of a lion (<i>kᵉpîr</i>); whoever provokes him to anger (<i>mitʿabbᵉrô</i>) puts his own life (<i>napšô</i>) at risk (<i>ḥôṭēʾ</i>).&#8221; Nearly identical to 19:12, but here the focus falls on the danger of provoking royal wrath — <i>ʿābar</i> in the hithpael (to make oneself pass over, to become enraged) describes the king going beyond normal limits in anger. <i>Ḥāṭāʾ</i> (to sin, to miss — used in 19:2 for missing the path) — provoking the king is to sin against one&#8217;s own life.</p>",
        "3": "<p>&#8220;It is an honor (<i>kābôd</i>) for a man to stay out of conflict (<i>šebet mêrîb</i>), but every fool (<i>ʾewîl</i>) will be drawn into quarreling (<i>yitgallāʿ</i>).&#8221; <i>Šebet</i> (sitting, staying — the quiet of non-engagement) in contrast to <i>rîb</i> (strife, lawsuit, quarrel — the legal word for dispute). <i>Gālaʿ</i> (to quarrel, to break out — hithpael: to involve oneself in a brawl) — the fool cannot resist the pull of a fight. Honor (<i>kābôd</i>) in Proverbs is consistently given to restraint and wisdom, not to aggressive self-assertion.</p>",
        "4": "<p>&#8220;The sluggard does not plow (<i>lōʾ-yaḥᵃrōš</i>) in the cold season (<i>ḥōrep</i>); at harvest (<i>qāṣîr</i>) he will look for food and find nothing.&#8221; <i>Ḥōrep</i> (autumn, the cold-wet season — the plowing season in Palestine) — the window for sowing is also the uncomfortable season. The sluggard&#8217;s avoidance of seasonal labor forfeits the harvest. The agricultural calendar is moralized: refusal to work in the hard season produces hunger in the good season. The verse is one of the most concrete images of the consequences of sloth.</p>",
        "5": "<p>&#8220;The counsel (<i>ʿēṣāh</i>) in a man&#8217;s heart (<i>bᵉleb-ʾîš</i>) is like deep water (<i>mayim ʿᵃmûqqîm</i>), but a man of understanding (<i>ʾîš tᵉbûnāh</i>) draws it out (<i>yidlennāh</i>).&#8221; Deep water requires a drawing-vessel to access; wisdom in the heart requires another wise person to draw it out. <i>Dālāh</i> (to draw water — the word used by the daughters of Reuel in Exod&#160;2:16) applied to drawing out a person&#8217;s inner wisdom. The image commends the kind of deep listening that extracts wisdom others cannot reach themselves.</p>",
        "6": "<p>&#8220;Many people proclaim (<i>yiqrāʾ</i>) their own loyalty (<i>ḥasdô</i>), but a truly faithful person — who can find (<i>mî yimṣāʾ</i>)?&#8221; The rhetorical question exposes the gap between claimed and actual <i>ḥesed</i>. <i>Ḥesed</i> (steadfast love, faithful loyalty) is the highest covenant virtue — many claim it, few embody it. The question &#8220;who can find?&#8221; echoes the search for wisdom herself (8:17) and the capable wife (31:10), placing faithful love in the category of rare and precious discoveries.</p>",
        "7": "<p>&#8220;A righteous man (<i>ṣaddîq</i>) who walks in his integrity (<i>bᵉtummô</i>) — blessed are his children (<i>ʾašrê bānāyw</i>) after him.&#8221; The <i>ʾašrê</i> (beatitude) formula applies not to the righteous man himself but to his children — they inherit the blessedness of their father&#8217;s integrity. <i>Tōm</i> (integrity — cf. 19:1) is the quality of wholeness that generates generational blessing (cf. Ps&#160;112:1&#8211;2). The father&#8217;s righteousness radiates outward into his posterity.</p>",
        "8": "<p>&#8220;A king who sits (<i>yōšēb</i>) on the throne of judgment (<i>kissēʾ-dîn</i>) scatters (<i>mᵉzāreh</i>) all evil with his eyes (<i>bᵉʿênāyw</i>).&#8221; <i>Zārāh</i> (to scatter, winnow — the act of throwing grain into the air to separate wheat from chaff; cf. Jer&#160;15:7; 31:10) applied to the king&#8217;s judicial discernment. The eyes that &#8220;scatter evil&#8221; are the penetrating gaze of the just judge who exposes and disperses wickedness by the mere act of righteous seeing. The king as winnower is a significant image for divine judgment (Matt&#160;3:12).</p>",
        "9": "<p>&#8220;Who can say, &#8216;I have made my heart pure (<i>zikkîtî libbî</i>); I am clean (<i>ṭāhartî</i>) from my sin&#8217;?&#8221; The rhetorical question expects the answer: no one. <i>Zākāh</i> (to be pure, clean — the root of <i>zāk</i>, pure; cf. Job&#160;15:14&#8211;16; 25:4) and <i>ṭāhēr</i> (to be ritually/morally clean) — both purity terms. The verse is the closest thing in Proverbs to a doctrine of universal sinfulness (cf. Ps&#160;51:5; Eccl&#160;7:20). No one can truthfully claim self-achieved moral purity; the honest person knows this about themselves.</p>",
        "10": "<p>&#8220;Unequal weights (<i>ʾeben wāʾāben</i>) and unequal measures (<i>ʾêpāh wᵉʾêpāh</i>) — both are detestable (<i>tôʿᵃbat</i>) to the LORD.&#8221; Two stones (weights) and two ephahs (dry measures) — the rigged scale. <i>Tôʿēbāh</i> (abomination — the strongest negative assessment term; cf. 3:32; 11:1; 12:22) places commercial fraud in the category of the most offensive sins against God. The Mosaic law is explicit (Lev&#160;19:35&#8211;36; Deut&#160;25:13&#8211;16; Amos&#160;8:5); Proverbs repeats the condemnation in 11:1; 20:23.</p>",
        "11": "<p>&#8220;Even a child (<i>naʿar</i>) is known (<i>yitnakkēr</i>) by his actions (<i>bᵉmaʿᵃlālāyw</i>), whether his conduct is pure (<i>zāk</i>) and right (<i>yāšār</i>).&#8221; <i>Nākar</i> (hithpael: to make oneself known, to be recognized — cf. 26:24; Gen&#160;42:7) — even at the child level, behavior reveals character. <i>Maʿᵃlāl</i> (deed, action — usually of significant or evil acts; cf. Isa&#160;1:16; Jer&#160;4:4; Ps&#160;77:11) — a person&#8217;s deeds are their introduction. The verse commends early character formation: the child already has a moral track record.</p>",
        "12": "<p>&#8220;The hearing ear (<i>ʾōzen šōmaʿat</i>) and the seeing eye (<i>ʿayin rōʾāh</i>) — the LORD made them both.&#8221; A creation-theology observation: the faculties by which wisdom enters the person — hearing and sight — are divine gifts. They carry an implicit obligation: organs made by God for wisdom-reception should be used for that purpose (cf. 17:24; Ps&#160;94:9; Isa&#160;6:9&#8211;10). The verse also grounds epistemology in creation: our capacity to perceive truly is a gift to be honored.</p>",
        "13": "<p>&#8220;Do not love sleep (<i>ʾal-tʾehab šēnāh</i>), or you will come to poverty (<i>tiwwārēš</i>); keep your eyes open (<i>pᵉqaḥ ʿênekā</i>) and you will have plenty of food (<i>tiśbaʿ-lāḥem</i>).&#8221; The sleep-love of the sluggard (cf. 6:9&#8211;11; 24:33&#8211;34; 19:15) produces poverty. <i>Pāqaḥ</i> (to open the eyes — the same word as when Hagar&#8217;s eyes were opened in Gen&#160;21:19; when blind eyes are opened in Isa&#160;35:5) — alertness is the opposite of sloth, and it produces abundance (<i>śābēaʿ</i>, fullness).</p>",
        "14": "<p>&#8220;Bad, bad (<i>raʿ raʿ</i>), says the buyer, but when he goes away, he boasts (<i>yithallel</i>) of his deal.&#8221; A scene from marketplace psychology — the buyer deprecates the merchandise to drive down the price, then brags about the bargain when safely away. No moral condemnation is explicit; the verse is an observation about commercial human nature and the strategic use of speech. <i>Hāllal</i> (hithpael: to boast — cf. 27:1&#8211;2; Ps&#160;34:2) — self-congratulation in private after deceptive speech in public.</p>",
        "15": "<p>&#8220;There is gold (<i>zāhāb</i>) and plenty of rubies (<i>pᵉnînîm</i>), but the lips that speak knowledge (<i>śiptê-daʿat</i>) are the truly precious thing (<i>kᵉlî yāqār</i>).&#8221; The three-level comparison: gold, rubies (already at the top of material value), and speech-that-gives-knowledge. <i>Kᵉlî yāqār</i> (a precious vessel, a rare implement) — knowledge-bearing speech is rarer and more valuable than the rarest physical commodity. The image carries the same rhetorical weight as 3:14&#8211;15 and 8:10&#8211;11.</p>",
        "16": "<p>&#8220;Take the garment (<i>beged</i>) of one who puts up security (<i>ʿārab</i>) for a stranger; hold it in pledge (<i>baḥᵃbōlēhû</i>) for those who are surety for foreigners.&#8221; The practical wisdom of collateral: surety for strangers is high-risk lending (cf. 6:1&#8211;5; 11:15; 17:18). <i>ʿĀrab</i> (to mix oneself in, to become surety — cf. Gen&#160;43:9) — pledging your own property for another&#8217;s debt. The advice is essentially: insist on security from reckless pledgers. The verse is repeated nearly verbatim in 27:13.</p>",
        "17": "<p>&#8220;Bread (<i>leḥem</i>) gained by deceit (<i>šeqer</i>) is sweet (<i>yiʿᵃrab</i>) to a man, but afterward (<i>ʾaḥᵃrîtô</i>) his mouth will be full of gravel (<i>ḥāṣāṣ</i>).&#8221; The temporal structure — sweet now, grit later — is the standard Proverbs pattern for folly&#8217;s attractive lies (cf. 5:3&#8211;4 for the adulteress). <i>ʿĀreb</i> (pleasant to the taste — cf. 3:24; 13:19) versus <i>ḥāṣāṣ</i> (gravel, small stones — what results when food turns to grit). Deceit masquerades as sweetness; its exposure fills the mouth with the inedible.</p>",
        "18": "<p>&#8220;Plans (<i>maḥᵃšābôt</i>) are established by seeking advice (<i>bᵉʿēṣāh</i>), and with wise guidance (<i>taḥbulôt</i>) you can wage war (<i>taʿᵃśeh milḥāmāh</i>).&#8221; <i>Maḥᵃšābāh</i> (plan — cf. 19:21) requires communal wisdom to be sound. <i>Taḥbulôt</i> (guidance, skillful steering — the nautical term from 1:5) now appears in a military context: strategic planning requires the wisdom of many counselors (cf. 11:14; 15:22; 24:6). The wisdom community, not the lone genius, is the source of reliable strategy.</p>",
        "19": "<p>&#8220;The gossip (<i>hôlēk rākîl</i>) reveals secrets (<i>gôleh-sôd</i>) wherever he goes; avoid anyone who talks too freely (<i>ʿim-pōteh śᵉpātāyw lōʾ titʿārab</i>).&#8221; <i>Rākîl</i> (slander, gossip — from <i>rākal</i>, to go about trading secrets; cf. Lev&#160;19:16; Jer&#160;6:28) — the gossip trades in other people&#8217;s private information. <i>Pātāh śᵉpātāyw</i> (one who opens his lips — talks freely, without restraint) — the advice is relational: avoid entering into confidences with those who cannot keep them (cf. 11:13; 18:8).</p>",
        "20": "<p>&#8220;Whoever curses (<i>mᵉqallel</i>) his father or his mother — his lamp (<i>nērô</i>) will be snuffed out (<i>yidʿak</i>) in deepest darkness (<i>bᵉʾîšôn ḥōšek</i>).&#8221; <i>Qālal</i> (piel: to curse, to treat as trivial and contemptible — the opposite of <i>kābēd</i>, to honor; Exod&#160;21:17) — the fifth commandment violation inverted. <i>Nēr</i> (lamp — the life-symbol; cf. 13:9; Job&#160;18:6; 21:17) extinguished &#8220;in the deepest darkness (<i>ʾîšôn</i> = the pupil of the eye, the darkest center)&#8221; — a particularly evocative phrase for total obliteration.</p>",
        "21": "<p>&#8220;An inheritance (<i>naḥᵃlāh</i>) quickly gained (<i>mᵉbōhelet</i>) at first will not be blessed (<i>lōʾ tᵉbōrak</i>) in the end.&#8221; <i>Bāhal</i> (pual: to be hastened, seized prematurely) — the inheritance obtained ahead of its proper time (by manipulation, impatience, or the death-wish toward parents) is cursed rather than blessed. The principle mirrors 13:11 (&#8220;wealth gotten hastily will dwindle&#8221;). Patient reception of what comes in due course is contrasted with greedy seizure of what is not yet yours.</p>",
        "22": "<p>&#8220;Do not say, &#8216;I will repay (<i>ʾᵃšallem-rāʿāh</i>) evil&#8217;; wait on (<i>qawwēh</i>) the LORD and he will deliver you (<i>wᵉyōšaʿ-lāk</i>).&#8221; <i>Qāwāh</i> (to wait, to hope — the same root as <i>tiqwāh</i>, hope, in 10:28; 11:7; 13:12) — the posture of patient trust rather than active vengeance. &#8220;He will deliver you (<i>yōšaʿ</i>)&#8221; — the salvation-verb, from the root of Yeshua/Joshua. The proverb anticipates the NT teaching on non-retaliation (Rom&#160;12:17&#8211;19, which quotes Deut&#160;32:35; cf. Matt&#160;5:39).</p>",
        "23": "<p>&#8220;Unequal weights (<i>ʾeben wāʾāben</i>) are detestable (<i>tôʿᵃbat</i>) to the LORD, and dishonest scales (<i>mōʾzᵉnê mirmāh</i>) are no good (<i>lōʾ-ṭôb</i>).&#8221; A near-repetition of v10, using slightly different vocabulary. <i>Mirmāh</i> (deceit, fraud — cf. Ps&#160;5:6; Zeph&#160;1:9) combined with <i>mōʾzᵉnayim</i> (scales, balance) — the dishonest scale embodies deceptive commercial practice. The repetition reinforces the absolute nature of the condemnation: commercial fraud is not a minor infraction but a divine abomination.</p>",
        "24": "<p>&#8220;A man&#8217;s steps (<i>miṣʿᵃdê-gāber</i>) are directed by the LORD (<i>mēYHWH</i>); how then can anyone understand (<i>yābîn</i>) his own path (<i>darkô</i>)?&#8221; <i>Gāber</i> (a strong man, a warrior — cf. Job&#160;3:3; 38:3) — even the strong man&#8217;s steps are divinely directed. The rhetorical question acknowledges the limits of human self-understanding: if God directs your steps, you cannot from your vantage point trace the full pattern of your own path. This does not produce fatalism but humility (cf. 16:9; 19:21).</p>",
        "25": "<p>&#8220;It is a snare (<i>mōqēš</i>) for a man to dedicate something rashly (<i>yālaʿ qōdeš</i>) and only afterward to reconsider (<i>ʾaḥar nᵉdārîm lᵉbaqqēr</i>).&#8221; <i>yālaʿ</i> (to swallow up, here in the sense of rash vowing — cf. Eccl&#160;5:2&#8211;6; Num&#160;30) — a hasty dedication to God becomes a trap when one later has second thoughts. <i>Neder</i> (vow — solemn promise to God; Num&#160;30:2; Deut&#160;23:21&#8211;23) cannot be undone casually. The wisdom is: think before you vow.</p>",
        "26": "<p>&#8220;A wise king (<i>melek ḥākām</i>) scatters (<i>mᵉzāreh</i>) the wicked and drives (<i>wayyāšeb</i>) the threshing wheel (<i>ʾôpān</i>) over them.&#8221; The winnowing image of v8 reappears: the just king&#8217;s justice is agricultural separation — wicked chaff from righteous grain. <i>ʾôpān</i> (wheel, threshing wheel) — the heavy wheel rolled over grain to separate it. The violence of the image (the wicked crushed by the threshing wheel) underscores that wise kingship cannot be purely passive benevolence; it must actively deal with wickedness.</p>",
        "27": "<p>&#8220;The human spirit (<i>nišmat ʾādām</i>) is the LORD&#8217;s lamp (<i>nēr-YHWH</i>), searching (<i>ḥōpēś</i>) all the innermost parts (<i>ḥadrê-bāṭen</i>) of a person.&#8221; <i>Nišmāh</i> (breath, spirit — cf. Gen&#160;2:7 where God breathed <i>nišmat ḥayyîm</i> into Adam) — the divine life-breath in the human person becomes God&#8217;s lamp for illuminating the inner self. <i>Ḥōpēś</i> (searching, probing — cf. Jer&#160;17:10; Ps&#160;139:1) — the divine-origin spirit searches the deepest chambers of the person&#8217;s interior. Conscience is here understood as the divine light within the human frame.</p>",
        "28": "<p>&#8220;Steadfast love (<i>ḥesed</i>) and faithfulness (<i>ʾĕmet</i>) preserve (<i>yiṣṣᵉrû</i>) the king, and his throne is upheld (<i>sāmûk</i>) by faithful love (<i>ḥesed</i>).&#8221; The paired covenant-character terms of Exod&#160;34:6&#8211;7 and Prov&#160;3:3 now applied to royal governance: the king who embodies <i>ḥesed-wĕʾĕmet</i> secures his throne. <i>ḥesed</i> (steadfast love) appears twice — framing the verse — emphasizing that covenant loyalty is the foundation, not military power or political cunning (cf. 29:14; Ps&#160;89:14).</p>",
        "29": "<p>&#8220;The glory (<i>tipʾeret</i>) of young men (<i>bᵉḥûrîm</i>) is their strength (<i>kōḥām</i>), but the honor (<i>hadar</i>) of old men (<i>zᵉqēnîm</i>) is their gray hair (<i>śêbāh</i>).&#8221; A complementarity observation: each stage of life has its appropriate glory. <i>Tipʾeret</i> (splendor, beauty, glory — cf. 4:9; Isa&#160;28:1; Ezek&#160;16:12) for the vigor of youth; <i>hādār</i> (dignity, majesty — cf. Ps&#160;96:6; 111:3) for the experienced elder. <i>Śêbāh</i> (gray hair — cf. 16:31; Lev&#160;19:32) is the badge of the <i>zāqēn</i> (elder/elders), who earned both the title and the dignity through years of lived wisdom.</p>",
        "30": "<p>&#8220;Painful blows (<i>ḥabburvôt-pāreʿ</i>) cleanse away (<i>yitmᵉraq</i>) evil (<i>bᵉrāʿ</i>); wounds (<i>makkôt</i>) reach the innermost parts (<i>ḥadrê-bāṭen</i>) of a person.&#8221; <i>Ḥabbûrāh</i> (welt, bruise — cf. Isa&#160;1:6; 53:5) and <i>makkāh</i> (blow, wound) — physical correction has a purifying effect (<i>yitmᵉraq</i> = to be scoured clean, polished). &#8220;Reaches the innermost parts&#8221; (<i>ḥadrê-bāṭen</i> — the same phrase as v27) — the correction that scours the surface also reaches the deepest interior. Discipline penetrates where words cannot.</p>"
    },
    "21": {
        "1": "<p>&#8220;The king&#8217;s heart (<i>leb-melek</i>) is in the hand of the LORD like channels of water (<i>pelagê-māyim</i>); he directs it (<i>yaṭṭennû</i>) wherever he pleases (<i>ʾᵃšer yaḥpōṣ</i>).&#8221; <i>Peleg</i> (irrigation channel, canal — cf. Ps&#160;1:3; 65:9; Isa&#160;30:25) — not the unpredictable flood but the directed stream. The agricultural image of irrigation channels emphasizes sovereign control: the king&#8217;s heart is not an autonomous power center but is channeled by God toward where he directs it. The most powerful human ruler is in the divine hand (cf. Isa&#160;44:28; 45:1).</p>",
        "2": "<p>&#8220;Every man thinks his own way (<i>darkô</i>) is right (<i>yāšār bᵉʿênāyw</i>), but the LORD weighs (<i>tōkēn</i>) the heart (<i>libbôt</i>).&#8221; <i>Yāšār bᵉʿênāyw</i> (straight in his own eyes — cf. 14:12; 16:2; 21:2b) — subjective moral self-assessment is inherently unreliable. <i>Tākan</i> (to weigh, measure — the verb of the divine balance; cf. 16:2; 24:12; 1&#160;Sam&#160;2:3; Job&#160;28:25) — the LORD&#8217;s weighing of hearts is the objective standard that corrects self-deception. The same thought as 16:2 with slightly different vocabulary.</p>",
        "3": "<p>&#8220;To do righteousness (<i>ʿᵃśôt ṣᵉdāqāh</i>) and justice (<i>mišpāṭ</i>) is more acceptable (<i>bāḥar</i>) to the LORD than sacrifice (<i>mizbāḥ</i>).&#8221; One of the clearest expressions in Proverbs of the prophetic critique of empty ritual (cf. 1&#160;Sam&#160;15:22; Hos&#160;6:6; Amos&#160;5:21&#8211;24; Isa&#160;1:11&#8211;17; Mic&#160;6:6&#8211;8). <i>Bāḥar</i> (to choose, prefer — the election verb: God prefers moral action to liturgical performance). The verse does not abolish sacrifice but insists that ethical action is its prerequisite and its meaning.</p>",
        "4": "<p>&#8220;Haughty eyes (<i>rûm-ʿênayim</i>) and a proud heart (<i>rᵉḥab-lēb</i>) — even the tillage (<i>nîr</i>) of the wicked — are sin (<i>ḥaṭṭāʾt</i>).&#8221; <i>Rûm ʿênayim</i> (high eyes — the lifted gaze of arrogance; cf. Ps&#160;18:27; 131:1; Prov&#160;6:17 where haughty eyes head the seven abominations). <i>Nîr</i> (freshly plowed field, fallow ground — cf. Jer&#160;4:3; Hos&#160;10:12) is difficult here: possibly &#8220;the lamp of the wicked&#8221; (an alternative reading) or &#8220;even the tillage of the wicked is sin&#8221; — even their productive work is morally contaminated. The second reading emphasizes that pride corrupts the whole person&#8217;s activity.</p>",
        "5": "<p>&#8220;The plans (<i>maḥšᵉbôt</i>) of the diligent (<i>ḥārûṣ</i>) lead to abundance (<i>limôtār</i>), but hasty action (<i>kol-ʾāṣ</i>) leads only to poverty (<i>lᵉmaḥsôr</i>).&#8221; <i>Ḥārûṣ</i> (diligent, decisive, incisive — from <i>ḥāraṣ</i>, to cut, decide sharply; cf. 10:4; 12:24) versus <i>ʾūṣ</i> (to hurry, to hasten — the anxiety-driven rush). <i>Môtār</i> (surplus, profit — what is left over after abundance) versus <i>maḥsôr</i> (lack, need — the state of deficiency; cf. 14:23; 28:19). Deliberate planning yields surplus; impulsive haste produces deficit.</p>",
        "6": "<p>&#8220;Treasures (<i>ʾôṣārôt</i>) gained by a lying tongue (<i>bᵉlāšôn šāqer</i>) are a fleeting vapor (<i>hebel niddāp</i>) — a deadly snare (<i>mᵉbaqšê māwet</i>).&#8221; <i>Hebel</i> (breath, vapor — Ecclesiastes&#8217; signature word; cf. Eccl&#160;1:2) applied to fraudulently-gained wealth: it evaporates as quickly as breath. The second image &#8220;deadly snare (<i>mᵉbaqšê māwet</i> = those who seek death)&#8221; — the pursuit of such treasures is not merely futile but lethal. Ill-gotten gains evaporate; their pursuit kills.</p>",
        "7": "<p>&#8220;The violence (<i>šōd</i>) of the wicked will drag (<i>yᵉgōrem</i>) them away, because they refuse (<i>mēʾᵃnû</i>) to do what is right (<i>mišpāṭ</i>).&#8221; <i>Šōd</i> (destruction, violence — from <i>šādad</i>, to devastate; cf. 24:2; Isa&#160;13:6) — the violent act becomes the agent of the violent person&#8217;s own destruction. <i>Gāram</i> (to drag away, cause — an unusual verb; cf. Num&#160;24:22) — the very violence the wicked commit sweeps them away. The refusal of justice (<i>mišpāṭ</i>) is the cause; being dragged away by one&#8217;s own violence is the effect.</p>",
        "8": "<p>&#8220;The way (<i>derek</i>) of the guilty person (<i>ʾîš wāwāh</i>) is crooked (<i>ḥᵃpakpak</i>) and strange (<i>wāzār</i>); the conduct (<i>poʿᵃlô</i>) of the pure (<i>zak</i>) is upright (<i>yāšār</i>).&#8221; <i>Wāwāh</i> (guilt, wrong — rare; cf. Job&#160;15:5) combined with <i>ḥᵃpakpak</i> (double-twisted, very crooked — an intensive reduplicated form of <i>hāpak</i>, to overturn) describes the maximally inverted moral direction. <i>Zak</i> (pure, clean — cf. 20:9; Job&#160;11:4) produces <i>yāšār</i> (straight, upright) — purity and moral straightness go together.</p>",
        "9": "<p>&#8220;It is better (<i>ṭôb</i>) to live in a corner of the roof (<i>bᵉpinnat-gāg</i>) than in a spacious house (<i>bêt ḥāber</i>) with a quarrelsome woman (<i>ʾēšet midyānîm</i>).&#8221; One of the domestic <i>ṭôb-min</i> (better-than) proverbs; cf. 21:19; 25:24 (near-identical); 19:13. <i>Pinnat-gāg</i> (corner of a flat roof — exposed, uncomfortable, crowded) versus the spacious shared house. <i>ʾēšet midyānîm</i> (a woman of quarreling/disputes — <i>midyān</i> from <i>dîn</i>, to judge/dispute; cf. 19:13; 27:15) — the structural parallel between domestic conflict and homelessness makes a sharp point about the value of peace over comfort.</p>",
        "10": "<p>&#8220;The wicked desire (<i>awwᵉtāh nepeš rāšāʿ</i>) evil; they show no kindness (<i>lōʾ-yuḥam</i>) even to their neighbor (<i>bᵉʿênāyw rēʿēhû</i>).&#8221; <i>ʾāwāh</i> (to desire, crave — the same root as <i>taʾᵃwāh</i>, desire; cf. 19:22) — the wicked&#8217;s appetite is oriented entirely toward evil. <i>Ḥānan</i> (to show grace, be kind — pual here: to be shown kindness) — in their neighbor&#8217;s eyes, they find no grace, show no grace. The total corruption of the social instincts: the wicked cannot be gracious to those nearest them.</p>",
        "11": "<p>&#8220;When a mocker (<i>lēṣ</i>) is punished (<i>baʿᵃnāš</i>), the naive (<i>peta&#702;î</i>) becomes wise (<i>yaḥkam</i>); when a wise person (<i>ḥākām</i>) receives instruction (<i>bᵉhaśkîl</i>), he gains knowledge (<i>yiqqaḥ-daʿat</i>).&#8221; Identical in structure to 19:25 — the three-level pedagogy of observing punishment (naive → wisdom), receiving direct instruction (wise → more knowledge). The mocker&#8217;s punishment is wasted on him but not on those watching; the wise person needs no theatrical punishment, only direct teaching.</p>",
        "12": "<p>&#8220;The righteous (<i>ṣaddîq</i>) perceive (<i>maśkîl</i>) the house of the wicked; God (<i>ʾĕlōhîm</i>) brings the wicked down (<i>mᵉsallēp</i>) to ruin.&#8221; The subject of &#8220;perceive&#8221; is ambiguous — &#8220;the Righteous One&#8221; (a title for God) or &#8220;the righteous person.&#8221; The MKT reads it as the righteous person who discerns what is happening in the wicked&#8217;s house; God acts as judge. <i>Sālap</i> (to overthrow, subvert — cf. 13:6; 19:3) — God is the agent of the wicked&#8217;s downfall, though the righteous perceives it.</p>",
        "13": "<p>&#8220;Whoever stops his ears (<i>ʾōṭēm ʾoznô</i>) at the cry of the poor (<i>mizzaʿᵃqat-dāl</i>) will himself cry out (<i>gam-hûʾ yiqrāʾ</i>) and not be heard (<i>wᵉlōʾ yēʿāneh</i>).&#8221; The retributive symmetry: the one who closes ears to the poor will find his own cries unanswered. <i>ʾāṭam</i> (to stop up, shut — cf. Isa&#160;33:15; Prov&#160;17:28 for stopping the ears as wisdom) — here used of a refusal to hear need. The verse draws a direct line from social deafness to unanswered prayer (cf. 1:24&#8211;28 where wisdom does not answer those who refused to hear).</p>",
        "14": "<p>&#8220;A secret gift (<i>mattān basseter</i>) calms (<i>yikpeh</i>) anger (<i>ʾap</i>), and a concealed bribe (<i>šōḥad baḥēq</i>) soothes fierce wrath (<i>ḥēmāh ʿazzāh</i>).&#8221; <i>Kāpāh</i> (to subdue, placate — rare; cf. Ps&#160;78:31; Prov&#160;26:20) — the quenching of anger by a discreet gift. The verse observes a social reality without explicit endorsement (cf. 17:8 for a similar observation). &#8220;In the bosom (<i>baḥēq</i>)&#8221; — tucked into the fold of the garment, out of sight. The secrecy is key: a private gift preserves face on both sides.</p>",
        "15": "<p>&#8220;It is a joy (<i>śimḥāh</i>) to the righteous (<i>laṣṣaddîq</i>) to do justice (<i>ʿᵃśôt mišpāṭ</i>), but it brings terror (<i>mᵉḥittāh</i>) to evildoers.&#8221; <i>Śimḥāh</i> (joy, gladness — cf. 10:28; 12:20; Deut&#160;16:11) — justice is something the righteous delight in, not merely endure. <i>Mᵉḥittāh</i> (dismay, ruin, terror — from <i>ḥātat</i>, to be shattered, dismayed; cf. 10:14&#8211;15) — the same justice that is joy to the righteous is experienced as destruction by the wicked. Justice is not neutral: its effect depends entirely on one&#8217;s moral position relative to it.</p>",
        "16": "<p>&#8220;Whoever wanders (<i>tōʿeh</i>) from the way of understanding (<i>midderek haśkēl</i>) will come to rest (<i>yānûaḥ</i>) among the dead (<i>biqhal rᵉpāʾîm</i>).&#8221; <i>Tāʿāh</i> (to wander, go astray — cf. Isa&#160;53:6; Ps&#160;119:176; Prov&#160;10:17) — the one who strays from wisdom&#8217;s way ends in Sheol. <i>Rᵉpāʾîm</i> (the shades of the dead — cf. 2:18; 9:18; Isa&#160;14:9) — Proverbs uses the Sheol imagery to underscore that wisdom&#8217;s path is a literal life-or-death matter. Rest among the dead is the final &#8220;home&#8221; of the wisdom-abandoner.</p>",
        "17": "<p>&#8220;Whoever loves pleasure (<i>ʾōhēb śimḥāh</i>) will be a poor man; whoever loves wine (<i>yayin</i>) and olive oil (<i>šemen</i>) will not grow rich.&#8221; The three luxury goods — pleasure, wine, oil — represent the good life pursued for its own sake. <i>Šemen</i> (olive oil — the cooking fat, cosmetic oil, and wealth-indicator of the ancient world) combined with wine forms the grain-wine-oil prosperity triad (Deut&#160;7:13). The lover of these things pursues consumption rather than production and becomes poor through expenditure without replenishment.</p>",
        "18": "<p>&#8220;The wicked (<i>rāšāʿ</i>) are a substitute (<i>kōper</i>) for the righteous, and the treacherous (<i>bôgēd</i>) take the place of the upright (<i>yāšār</i>).&#8221; <i>Kōper</i> (ransom, substitute — the payment that releases another from an obligation or penalty; cf. Exod&#160;21:30; 30:12; Num&#160;35:31) — the wicked function as the ransom/substitute for the righteous. The verse expresses a retributive economy: what the righteous escaped falls upon the wicked (cf. Isa&#160;43:3&#8211;4 where God gives Egypt as Israel&#8217;s ransom). The treacherous receive what the upright were spared.</p>",
        "19": "<p>&#8220;It is better to live in a desert (<i>ʾereṣ-midbār</i>) than with a quarrelsome (<i>midyānîm</i>) and angry (<i>kaʿas</i>) woman.&#8221; The escalation from 21:9 (corner of a roof) to the desert — a place of total barrenness — shows how intolerable the quarrelsome domestic environment is by comparison. <i>Kaʿas</i> (vexation, anger — cf. 12:16; 17:25; 1&#160;Sam&#160;1:6) combined with constant quarreling creates a domestic environment worse than wilderness isolation. The proverb is not anti-woman but rather an extreme statement about the unbearability of constant conflict.</p>",
        "20": "<p>&#8220;Precious treasure (<i>ʾôṣār neḥmād</i>) and oil (<i>šemen</i>) are stored (<i>linwēh</i>) in the house of the wise (<i>ḥākām</i>), but a fool (<i>ʾewîl</i>) quickly squanders (<i>yᵉballa&#702;ennû</i>) them.&#8221; <i>Neḥmād</i> (precious, desirable — from <i>ḥāmad</i>, to desire; cf. Gen&#160;3:6; Exod&#160;20:17) — the wise person accumulates desirable things through self-discipline. <i>Bālaʿ</i> (to swallow, consume quickly — cf. 1:12; 19:28) — the fool swallows his inheritance in a gulp. The contrast is between wise preservation and foolish consumption.</p>",
        "21": "<p>&#8220;Whoever pursues (<i>rōdēp</i>) righteousness (<i>ṣᵉdāqāh</i>) and steadfast love (<i>ḥesed</i>) will find life (<i>yimṣāʾ ḥayyîm</i>), righteousness, and honor (<i>kābôd</i>).&#8221; <i>Rādap</i> (to pursue, chase — the same verb used of enemies pursuing in warfare; Deut&#160;30:7; Ps&#160;23:6) — righteousness and <i>ḥesed</i> are not passive acquisitions but the objects of an active chase. The triad of rewards — life, righteousness, honor — echoes 3:16 (long life, wealth, honor in wisdom&#8217;s hands). The pursuit of virtue finds virtue itself, plus life and honor as the bonus.</p>",
        "22": "<p>&#8220;A wise man (<i>ḥākām</i>) can take (<i>ʿālāh</i>) a city of warriors (<i>ʿîr gibbōrîm</i>) and bring down (<i>wayyōred</i>) the stronghold (<i>ʿōz mibtaḥô</i>) in which they trust.&#8221; Wisdom over force — the intellectual over the military. <i>ʿāzāz mibtāḥô</i> (the strength in which they trust — <i>mibtāḥ</i> from <i>bāṭaḥ</i>, to trust) — the warriors trusted in their fortified strength; wisdom undermines that confidence. This wisdom-conquers-war motif recurs in Eccl&#160;9:13&#8211;16 (the poor wise man who saved the city).</p>",
        "23": "<p>&#8220;Whoever guards (<i>šōmēr</i>) his mouth (<i>pîhû</i>) and tongue (<i>lᵉšônô</i>) keeps himself (<i>šōmēr</i>) out of trouble (<i>miṣṣārôt napšô</i>).&#8221; The double use of <i>šāmar</i> (to guard, keep) ties self-protection to speech-control: guarding the mouth is guarding the self. <i>Ṣārāh</i> (trouble, distress, adversity — cf. Ps&#160;107:6, 13, 19) — most of what afflicts people from outside is set in motion by what comes out of their own mouths (cf. 13:3; 18:21; Jas&#160;3:2&#8211;6).</p>",
        "24": "<p>&#8220;Proud, haughty, &#8216;Scoffer&#8217; is his name — he acts with overweening arrogance (<i>bᵉʿebrāt-zādôn yᵉʿāśeh</i>).&#8221; The mocker receives a taxonomy: <i>zēd</i> (proud, presumptuous — cf. Ps&#160;19:13; 86:14; 119:21) + <i>yāhîr</i> (haughty — rare; cf. Hab&#160;2:5) = <i>lēṣ</i> (scoffer/mocker — the characteristic Proverbs fool-type). <i>ʿebrāt-zādôn</i> (the overflow of arrogance) — the mocker does not merely have pride; he is defined by its excess. The three names describe a single intensifying character: proud → haughty → mocker-by-nature.</p>",
        "25": "<p>&#8220;The craving (<i>taʾᵃwat</i>) of a sluggard (<i>ʿāṣēl</i>) will be his death (<i>tᵉmîtennû</i>), because his hands refuse (<i>mēʾᵃnû</i>) to work.&#8221; <i>Taʾᵃwāh</i> (desire, craving — cf. 19:22) — the sluggard has desires but no labor to achieve them; the gap between craving and effort produces death. <i>Māʾan</i> (to refuse — the word of stubborn refusal, used of Israel refusing to hear in Jer&#160;5:3; 8:5; cf. Exod&#160;7:14) — the refusal to work is moral, not merely laziness. Death-by-unfulfilled-craving is the ultimate fate of the sloth.</p>",
        "26": "<p>&#8220;The wicked covet (<i>hit&#702;awwāh taʾᵃwāh</i>) all day long, but the righteous give generously (<i>nôtēn</i>) without holding back (<i>wᵉlōʾ yaḥśôk</i>).&#8221; <i>ʾāwāh</i> (hithpael: to desire intensely for oneself — the intensive self-directed desire) — the wicked want constantly; the righteous give constantly. The contrast is not between activity and inactivity but between the direction of the impulse: inward grasping versus outward giving (cf. Luke&#160;12:21; 2&#160;Cor&#160;9:6&#8211;9).</p>",
        "27": "<p>&#8220;The sacrifice (<i>zebaḥ</i>) of the wicked (<i>rᵉšāʿîm</i>) is detestable (<i>tôʿᵃbāh</i>); how much more (<i>ʾap kî</i>) when offered with evil intent (<i>bᵉzimmāh</i>).&#8221; The priori argument: even their ordinary sacrifice is detestable (cf. 15:8; Isa&#160;1:11&#8211;13); when their sacrifice accompanies a specific evil scheme (<i>zimmāh</i> = evil plan, lewdness; cf. Lev&#160;18:17; Ezek&#160;16:43) the abomination is multiplied. The use of sacrifice as cover for moral corruption is condemned in the strongest terms (cf. 21:3; 1&#160;Sam&#160;15:22).</p>",
        "28": "<p>&#8220;A false witness (<i>ʿēd-kᵉzābîm</i>) will perish, but whoever listens (<i>šōmēaʿ</i>) speaks truthfully (<i>lānetsaḥ</i>) and endures.&#8221; The final summary on false witness in this section. <i>Nêṣaḥ</i> (perpetuity, endurance, forever — cf. 2&#160;Sam&#160;2:26; Amos&#160;1:11; Jer&#160;3:5) — the truthful witness &#8220;endures forever.&#8221; The one who first listens (takes in truth accurately) and then speaks (conveys it faithfully) has a lasting presence, while the false witness perishes.</p>",
        "29": "<p>&#8220;A wicked man puts on a bold face (<i>heʿez pānāyw</i>), but the upright person carefully considers (<i>yāḵîn</i>) his way.&#8221; <i>ʿāzaz pānîm</i> (to make the face bold/hard — the brazen, shameless face of the wicked; cf. 7:13; Jer&#160;3:3; Prov&#160;17:1) — the wicked man&#8217;s confidence comes from shamelessness, not integrity. <i>Kûn</i> (hiphil: to establish, prepare, consider carefully) — the upright person takes care with the direction of his steps, unlike the brazenly reckless wicked.</p>",
        "30": "<p>&#8220;There is no wisdom (<i>ḥokmāh</i>), no understanding (<i>tᵉbûnāh</i>), no counsel (<i>ʿēṣāh</i>) that can stand against (<i>lᵉneged</i>) the LORD.&#8221; The three primary wisdom terms — <i>ḥokmāh, tᵉbûnāh, ʿēṣāh</i> — appear together (cf. Isa&#160;11:2; Job&#160;28:20&#8211;28) as a triad that, however great, cannot stand against God. The verse is the theological culmination of ch21: human wisdom, understanding, and counsel are genuine goods but bounded; the LORD exceeds and governs all of them (cf. 19:21; 21:1; Isa&#160;40:13&#8211;14; 46:10).</p>",
        "31": "<p>&#8220;The horse (<i>hassûs</i>) is made ready (<i>mûkān</i>) for the day of battle (<i>lᵉyôm milḥāmāh</i>), but victory (<i>yᵉšûʿāh</i>) belongs to the LORD.&#8221; The military image: the horse is the ancient equivalent of armored cavalry — the most powerful human war-technology. <i>Yᵉšûʿāh</i> (salvation, victory — the root of the name Yeshua/Joshua; here the military sense is primary: the victory that decides the battle belongs to God, not to equipment or human strategy). Ps&#160;33:17 (&#8220;a horse is a vain hope for salvation&#8221;) and 20:7 (&#8220;some trust in chariots, some in horses, but we trust in the name of the LORD&#8221;) stand in the same tradition. The most powerful instrument of war cannot guarantee what only divine sovereignty can give.</p>"
    }
}

existing = load_comm('mkt-original', 'proverbs')
merge_comm(existing, new_data)
save_comm('mkt-original', 'proverbs', existing)

for ch in sorted(new_data.keys(), key=int):
    vv = new_data[ch]
    have = sum(1 for v in vv if v in existing.get(ch, {}))
    print(f'  ch{ch}: {have}/{len(vv)} verses present')
